    mp:{img:'tulzjp.png',en:'Military Police',th:'ตำรวจทหาร'},
    garrison:{img:'k7spvf.png',en:'Garrison',th:'กองทหารรักษากำแพง'},
    stationary:{img:'k7spvf.png',en:'Garrison',th:'กองทหารรักษากำแพง'}
  };

  var MODELS=th?{
    blade:'ODM — ใบดาบมาตรฐาน',
    ap_gun:'ODM — ปืนต่อต้านบุคคล',
    thunder_spear:'ODM — ทันเดอร์สเปียร์',
