    name:'Name',age:'Age',gender:'Gender',heritage:'Heritage',
    rank:'Rank',branch:'Branch',role:'Role',residence:'Residence',year:'Year',
    gas:'Gas',blades:'Blades',rounds:'Rounds',tspear:'Thunder Spears',
    odm:'ODM Gear',notEquipped:'Not equipped',weapons:'Weapons',
    unknown:'Unknown',inheritor:'Current Inheritor',
    tkills:'Titans Slain',hkills:'Lives Taken'
  };

  var bKey=((D.branch||'')+'').toLowerCase().replace(/[\s-]/g,'_');
  var bInfo=BRANCHES[bKey];
  var insCode=D.insignia_code || (bInfo?bInfo.img:'');
  var ins=g('ins');
  if(insCode){ ins.src='https://files.catbox.moe/'+insCode; }
  else { ins.classList.add('hide'); }
  var branchLabel = bInfo ? (th?bInfo.th:bInfo.en) : (D.branch||'');

  g('nm').textContent=(D.name||L.unknown);
  g('rk').textContent=[D.rank, branchLabel].filter(Boolean).join(' · ');

  var tabs=g('tabs'), panes=g('panes');
  var tabSpec=[{k:'profile',label:L.profile},{k:'equipment',label:L.equipment}];
  if(D.titan_power) tabSpec.push({k:'titan',label:L.titan});

  tabSpec.forEach(function(t,i){
